-- ============================================================
-- Import Book1.xlsx candidate tracker (312 unique candidates, 322 Excel rows)
-- Uploaded by: Khushi (users.username = 'khushi')
-- Source file: Book1.xlsx
--
-- Color mapping (row-level, any column):
--   Blue   #9BC2E6 -> Hired
--   Green  #92D050 -> Selected (shortlisted, NOT hired)
--   Red    #FF0000 -> Rejected (none in file; inferred from Status/Remarks)
--
-- Generated by: backend/scripts/generate_book1_import_sql.py
-- ============================================================

SET NAMES utf8mb4;
SET @import_started_at = NOW();
SET @khushi_user_id = (SELECT id FROM users WHERE username = 'khushi' LIMIT 1);

-- Prerequisites (MySQL 5.7 / MariaDB compatible — skips existing columns)
SET @sql = IF((SELECT COUNT(*) FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'candidates' AND COLUMN_NAME = 'main_stage') = 0, 'ALTER TABLE `candidates` ADD COLUMN `main_stage` VARCHAR(50) NULL AFTER stage', 'SELECT 1');
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @sql = IF((SELECT COUNT(*) FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'candidates' AND COLUMN_NAME = 'sub_stage') = 0, 'ALTER TABLE `candidates` ADD COLUMN `sub_stage` VARCHAR(50) NULL AFTER main_stage', 'SELECT 1');
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @sql = IF((SELECT COUNT(*) FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'candidates' AND COLUMN_NAME = 'uploaded_by') = 0, 'ALTER TABLE `candidates` ADD COLUMN `uploaded_by` INT(11) NULL AFTER assigned_to', 'SELECT 1');
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

ALTER TABLE candidates
  MODIFY COLUMN stage ENUM(
    'Applied','Follow Up','Screening','Interview','Offer','Hired',
    'On Hold','Rejected','No Show - Interview','No Show - Onboarding',
    'Last Minute Back Out','Profile Not Matched','Selected'
  ) NOT NULL DEFAULT 'Applied';

ALTER TABLE hr_notes
  MODIFY COLUMN stage ENUM(
    'Applied','Follow Up','Screening','Interview','Offer','Hired',
    'On Hold','Rejected','No Show - Interview','No Show - Onboarding',
    'Last Minute Back Out','Profile Not Matched','Selected'
  ) NOT NULL DEFAULT 'Applied';

SELECT IF(@khushi_user_id IS NULL,
  (SELECT 'ERROR: Khushi user not found. Run backend/migrations/add_recruiter_khushi.sql first.' AS message),
  (SELECT CONCAT('Khushi user id = ', @khushi_user_id) AS message));

-- Optional safety backup
CREATE TABLE IF NOT EXISTS candidates_backup_book1_import AS
SELECT * FROM candidates WHERE 1 = 0;

START TRANSACTION;

VALUES (@khushi_user_id, 'Book1.xlsx', 312, 312, 0, 0, @import_started_at);
SET @import_log_id = LAST_INSERT_ID();

























































































































































































































































































































-- Refresh applicant_count on affected job postings
UPDATE job_postings SET applicant_count = (SELECT COUNT(*) FROM candidates WHERE job_id = 4), updated_at = NOW() WHERE id = 4;
