UPDATE job_postings SET applicant_count = (SELECT COUNT(*) FROM candidates WHERE job_id = 19), updated_at = NOW() WHERE id = 19;
UPDATE job_postings SET applicant_count = (SELECT COUNT(*) FROM candidates WHERE job_id = 23), updated_at = NOW() WHERE id = 23;
UPDATE job_postings SET applicant_count = (SELECT COUNT(*) FROM candidates WHERE job_id = 25), updated_at = NOW() WHERE id = 25;
UPDATE job_postings SET applicant_count = (SELECT COUNT(*) FROM candidates WHERE job_id = 26), updated_at = NOW() WHERE id = 26;
UPDATE job_postings SET applicant_count = (SELECT COUNT(*) FROM candidates WHERE job_id = 28), updated_at = NOW() WHERE id = 28;
UPDATE job_postings SET applicant_count = (SELECT COUNT(*) FROM candidates WHERE job_id = 30), updated_at = NOW() WHERE id = 30;

COMMIT;

-- ============================================================
-- Verification queries
-- ============================================================
SELECT stage, COUNT(*) AS cnt FROM candidates
WHERE uploaded_by = @khushi_user_id AND source = 'Manual Entry'
  AND created_at >= @import_started_at
GROUP BY stage ORDER BY cnt DESC;

SELECT j.id, j.title, COUNT(c.id) AS imported_count
FROM candidates c
JOIN job_postings j ON j.id = c.job_id
WHERE c.uploaded_by = @khushi_user_id
  AND c.created_at >= @import_started_at
GROUP BY j.id, j.title
ORDER BY imported_count DESC;

